const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

// Validate API key
const apiKey = headers['x-api-key'] || headers['authorization']?.replace('Bearer ', '');
const validKeys = [
  process.env.WEBHOOK_API_KEY_1,
  process.env.WEBHOOK_API_KEY_2,
  process.env.WEBHOOK_API_KEY_3
].filter(Boolean);

if (validKeys.length > 0 && !validKeys.includes(apiKey)) {
  return [{ json: { valid: false, error: 'Invalid API key', code: 401 } }];
}

// Validate required fields
const required = ['title', 'price', 'property_type'];
const missing = required.filter(f => !body[f]);

if (missing.length > 0) {
  return [{ json: { valid: false, error: `Missing required fields: ${missing.join(', ')}`, code: 400 } }];
}

// Sanitize and normalize
const listing = {
  valid: true,
  listing_id: body.listing_id || `webhook_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
  title: String(body.title || '').substring(0, 255),
  price: parseFloat(body.price) || 0,
  price_currency: body.price_currency || 'ZAR',
  bedrooms: parseInt(body.bedrooms) || 0,
  bathrooms: parseInt(body.bathrooms) || 0,
  property_type: String(body.property_type || 'unknown').toLowerCase(),
  suburb: String(body.suburb || '').substring(0, 100),
  city: String(body.city || '').substring(0, 100),
  province: String(body.province || '').substring(0, 100),
  size_sqm: parseFloat(body.size_sqm) || 0,
  url: String(body.url || '').substring(0, 500),
  source: String(body.source || 'webhook').substring(0, 50),
  description: String(body.description || '').substring(0, 5000),
  agent_name: String(body.agent_name || '').substring(0, 100),
  agent_phone: String(body.agent_phone || '').substring(0, 20),
  agent_email: String(body.agent_email || '').substring(0, 100),
  images: Array.isArray(body.images) ? body.images.slice(0, 20) : [],
  features: body.features || {},
  latitude: parseFloat(body.latitude) || null,
  longitude: parseFloat(body.longitude) || null,
  received_at: new Date().toISOString(),
  status: 'active'
};

// Validate price range
if (listing.price < 0 || listing.price > 500000000) {
  return [{ json: { valid: false, error: 'Price out of valid range (0 - 500,000,000)', code: 400 } }];
}

return [{ json: listing }];

